starter_code:
#include <iostream>

int main() {
    int inches{};
    // Your code here
    return 0;
}

solution_code:
#include <iostream>

int main() {
    int inches{};
    std::cin >> inches;

    int feet{ inches / 12 };
    int remaining{ inches % 12 };

    std::cout << "Feet: " << feet << '\n';
    std::cout << "Remaining inches: " << remaining << '\n';

    return 0;
}

